params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_初診_診療科 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"ゲノム診療科": "1", "腫瘍内科": "1", "血液内科": "1", "緩和ケア内科": "1", "リハビリテーション科": "1", "看護外来": "1", "女性専用外来": "1", "救急診療科": "1", "救命・集中治療科": "1", "小児科": "1", "リウマチ外科": "2", "リウマチ膠原病内科": "2"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 3 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_初診_診療科");
var mapping = {"ゲノム診療科": "1", "腫瘍内科": "1", "血液内科": "1", "緩和ケア内科": "1", "リハビリテーション科": "1", "看護外来": "1", "女性専用外来": "1", "救急診療科": "1", "救命・集中治療科": "1", "小児科": "1", "リウマチ外科": "2", "リウマチ膠原病内科": "2"};
var group = mapping[input];
if (!group) { group = "3"; }
$runner.setResult(group);
